class Solution:
    def repeatedStringMatch(self, a: str, b: str) -> int:
        if not b:
            return 0
        n, m = len(a), len(b)
        min_repeats = (m + n - 1) // n
        for k in (min_repeats, min_repeats + 1):
            if b in (a * k):
                return k
        return -1

